import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { teachersAPI } from '../../services/api';
import Card from '../../components/common/Card';
import toast from 'react-hot-toast';
import { BookOpen, Users, CheckCircle, XCircle, Clock } from 'lucide-react';

const CapstoneManagement = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const response = await teachersAPI.getById(user.id);
      if (response.data.success) {
        setProfile(response.data.teacher);
        setRequests(response.data.teacher.capstoneGroups || []);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateRequest = async (groupId, status) => {
    try {
      await teachersAPI.updateCapstoneRequest(groupId, status);
      toast.success(`Request ${status.toLowerCase()}`);
      fetchData();
    } catch (error) {
      toast.error('Failed to update request');
    }
  };

  const toggleAvailability = async () => {
    try {
      await teachersAPI.toggleCapstoneAvailability(
        profile.id, 
        !profile.capstone_adviser_available
      );
      toast.success('Availability updated');
      fetchData();
    } catch (error) {
      toast.error('Failed to update availability');
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  const pendingRequests = requests.filter(r => r.status === 'Pending');
  const approvedGroups = requests.filter(r => r.status === 'Approved');

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-secondary-800">Capstone Management</h1>
        <button
          onClick={toggleAvailability}
          className={`px-4 py-2 rounded-lg font-medium transition-colors ${
            profile?.capstone_adviser_available
              ? 'bg-green-100 text-green-700 hover:bg-green-200'
              : 'bg-secondary-100 text-secondary-700 hover:bg-secondary-200'
          }`}
        >
          {profile?.capstone_adviser_available ? 'Available for Advising' : 'Not Available'}
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card>
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-yellow-100 rounded-lg flex items-center justify-center">
              <Clock className="w-6 h-6 text-yellow-600" />
            </div>
            <div>
              <p className="text-sm text-secondary-500">Pending Requests</p>
              <p className="text-2xl font-bold text-secondary-800">{pendingRequests.length}</p>
            </div>
          </div>
        </Card>
        <Card>
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center">
              <CheckCircle className="w-6 h-6 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-secondary-500">Approved Groups</p>
              <p className="text-2xl font-bold text-secondary-800">{approvedGroups.length}</p>
            </div>
          </div>
        </Card>
        <Card>
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center">
              <Users className="w-6 h-6 text-blue-600" />
            </div>
            <div>
              <p className="text-sm text-secondary-500">Total Groups</p>
              <p className="text-2xl font-bold text-secondary-800">{requests.length}</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Pending Requests */}
      <Card title="Pending Requests">
        {pendingRequests.length > 0 ? (
          <div className="space-y-4">
            {pendingRequests.map((request) => (
              <div
                key={request.id}
                className="flex items-center justify-between p-4 bg-yellow-50 border border-yellow-200 rounded-lg"
              >
                <div>
                  <h4 className="font-medium text-secondary-800">{request.group_name}</h4>
                  <p className="text-sm text-secondary-500">Members: {request.members || 'N/A'}</p>
                  <p className="text-sm text-secondary-500">
                    Requested: {new Date(request.request_date).toLocaleDateString()}
                  </p>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => handleUpdateRequest(request.id, 'Approved')}
                    className="p-2 bg-green-100 text-green-700 rounded-lg hover:bg-green-200"
                  >
                    <CheckCircle className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => handleUpdateRequest(request.id, 'Rejected')}
                    className="p-2 bg-red-100 text-red-700 rounded-lg hover:bg-red-200"
                  >
                    <XCircle className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-8 text-secondary-500">
            <Clock className="w-12 h-12 mx-auto mb-3 text-secondary-300" />
            <p>No pending requests</p>
          </div>
        )}
      </Card>

      {/* Approved Groups */}
      <Card title="Approved Groups">
        {approvedGroups.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-secondary-200">
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Group Name</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Members</th>
                  <th className="text-left py-3 px-4 text-secondary-600 font-medium">Approved Date</th>
                </tr>
              </thead>
              <tbody>
                {approvedGroups.map((group) => (
                  <tr key={group.id} className="border-b border-secondary-100">
                    <td className="py-3 px-4 font-medium">{group.group_name}</td>
                    <td className="py-3 px-4 text-secondary-600">{group.members || 'N/A'}</td>
                    <td className="py-3 px-4 text-secondary-600">
                      {group.approval_date ? new Date(group.approval_date).toLocaleDateString() : 'N/A'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center py-8 text-secondary-500">
            <BookOpen className="w-12 h-12 mx-auto mb-3 text-secondary-300" />
            <p>No approved groups yet</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default CapstoneManagement;
